import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns 5 G processing fee for an empty item list", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("returns base premium plus fee for a single sword", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("returns base premium plus fee for a single amulet", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it.todo("returns base premium plus fee for a single staff");
    it.todo("returns base premium plus fee for a single potion");
    it.todo("returns base premium plus fee for a single component (rune)");
    it.todo("sums base premiums for multiple different items");
  });

  describe("Quote - component blocks", () => {
    it.todo("charges 60 G for a block of exactly 3 alike components");
    it.todo("charges individual premiums for 2 alike components (no block)");
    it.todo("charges individual premiums for 4 alike components (no block)");
    it.todo("treats different component types separately for block eligibility");
    it.todo("applies two separate blocks for 3 runes and 3 moonstones");
  });

  describe("Quote - item-specific modifiers", () => {
    it.todo("adds 50% cursed surcharge to the cursed item base premium");
    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
    it.todo("applies both cursed and high-enchantment surcharges to the same item");
    it.todo("applies item-specific surcharges only to the affected item in a multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("does not apply loyalty discount for customer with < 2 years");
    it.todo("applies 10% first insurance surcharge to every quote");
    it.todo("applies 15% follow-up discount on second and subsequent contracts");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up in MHPCO's favor");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword yields 165 G");
    it.todo("long-standing customer second contract with cursed high-enchantment sword yields 160 G");
  });

  describe("Claim - basic payout", () => {
    it.todo("applies 100 G deductible to a single damage event");
    it.todo("reimburses damage to a regular item fully minus deductible");
    it.todo("applies deductible per damaged item in a multi-damage event");
  });

  describe("Claim - enchantment and material clauses", () => {
    it.todo("reimburses at 50% for items with enchantment >= 8");
    it.todo("reimburses fully for dragon-material items");
    it.todo("applies 50% rule when both high-enchantment and dragon-material apply");
    it.todo("reimburses dragon-material item fully when enchantment < 8");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("tracks remaining cap across multiple claims on same policy");
  });

  describe("Claim - payout rounding", () => {
    it.todo("rounds payout down in MHPCO's favor");
  });

  describe("Validation", () => {
    it.todo("rejects unknown item type in quote");
    it.todo("rejects claim referencing item not in policy");
    it.todo("rejects negative damage amount");
    it.todo("rejects more damage entries of a type than policy covers");
  });

  describe("CLI", () => {
    it.todo("processes a full scenario with quote and claim via CLI");
  });
});

