interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface Step {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface StepResult {
  premium: number;
}

interface ScenarioResult {
  results: StepResult[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    let basePremium = 0;
    for (const item of step.items) {
      basePremium += BASE_PREMIUMS[item.type];
    }
    const firstInsuranceSurcharge = basePremium * 0.1;
    const premium = Math.ceil(basePremium + firstInsuranceSurcharge) + 5;
    return { premium };
  });
  return { results };
}

