interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface Step {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface StepResult {
  premium: number;
}

interface ScenarioResult {
  results: StepResult[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const CURSED_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const calculateQuotePremium = (items: Item[]): number => {
  let basePremium = 0;
  let itemSurcharges = 0;
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      const itemBasePremium = BASE_PREMIUMS[item.type];
      basePremium += itemBasePremium;
      if (item.cursed) {
        itemSurcharges += itemBasePremium * CURSED_SURCHARGE_RATE;
      }
      if (item.enchantment >= 5) {
        itemSurcharges += itemBasePremium * 0.3;
      }
    }
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    basePremium += count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUMS[type];
  }

  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge) + PROCESSING_FEE;
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => ({
    premium: calculateQuotePremium(step.items),
  }));
  return { results };
};

