export const processScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const policies: { items: Item[]; insuranceSum: number; remainingCap: number }[] = [];
  const results = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount);
      const insuranceSum = step.items.reduce(
        (sum: number, item: Item) => sum + INSURANCE_VALUES[item.type],
        0,
      );
      policies[index] = { items: step.items, insuranceSum, remainingCap: insuranceSum * 2 };
      quoteCount++;
      return { premium };
    } else {
      const policy = policies[step.policy];
      let totalPayout = 0;
      for (const damage of step.incident.damages) {
        const payout = damage.amount - DEDUCTIBLE;
        totalPayout += Math.max(0, payout);
      }
      totalPayout = Math.min(totalPayout, policy.remainingCap);
      policy.remainingCap -= totalPayout;
      return { payout: totalPayout, remainingCap: policy.remainingCap };
    }
  });
  return { results };
};

