interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface Damage {
  itemType: string;
  amount: number;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface ClaimStep {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: Damage[] };
}

type Step = QuoteStep | ClaimStep;

interface Policy {
  items: Item[];
  insuranceSum: number;
  remainingCap: number;
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ClaimResult {
  payout: number;
  remainingCap: number;
}

interface ScenarioResult {
  results: (QuoteResult | ClaimResult)[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

const calculateQuotePremium = (items: Item[], customer: { yearsWithMHPCO: number }, quoteIndex: number): number => {
  let basePremium = 0;
  let itemSurcharges = 0;
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      const itemBasePremium = BASE_PREMIUMS[item.type];
      basePremium += itemBasePremium;
      if (item.cursed) {
        itemSurcharges += itemBasePremium * CURSED_SURCHARGE_RATE;
      }
      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
        itemSurcharges += itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
      }
    }
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    basePremium += count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUMS[type];
  }

  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
  const followUpDiscount = quoteIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
};

const CAP_MULTIPLIER = 2;

const calculateInsuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);

const calculateClaimPayout = (step: ClaimStep, policy: Policy): ClaimResult => {
  let totalPayout = 0;
  for (const damage of step.incident.damages) {
    const policyItem = policy.items.find((i) => i.type === damage.itemType);
    let reimbursement = damage.amount;
    if (policyItem && policyItem.enchantment >= 8) {
      reimbursement = damage.amount * 0.5;
    }
    totalPayout += Math.max(0, reimbursement - DEDUCTIBLE);
  }
  totalPayout = Math.min(totalPayout, policy.remainingCap);
  policy.remainingCap -= totalPayout;
  return { payout: totalPayout, remainingCap: policy.remainingCap };
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const policies: Policy[] = [];
  const results = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount);
      const insuranceSum = calculateInsuranceSum(step.items);
      policies[index] = { items: step.items, insuranceSum, remainingCap: insuranceSum * CAP_MULTIPLIER };
      quoteCount++;
      return { premium };
    }
    return calculateClaimPayout(step, policies[step.policy]);
  });
  return { results };
};

{
  "name": "tdd-experiment-run",
  "type": "module",
  "scripts": {
    "test": "vitest run",
    "test:unit:basic": "vitest run",
    "test:watch": "vitest",
    "test:coverage": "vitest run --coverage --coverage.reporter=json-summary"
  },
  "devDependencies": {
    "typescript": "^5.3.0",
    "tsx": "^4.7.0",
    "vitest": "^1.0.0",
    "@vitest/coverage-v8": "^1.0.0",
    "eslint": "^9.0.0",
    "eslint-plugin-sonarjs": "^1.0.0",
    "typescript-eslint": "^8.0.0"
  },
  "pnpm": {
    "onlyBuiltDependencies": ["esbuild"]
  }
}

{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ESNext",
    "moduleResolution": "Node",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "outDir": "./dist"
  },
  "include": ["src/**/*"]
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    include: ['src/**/*.spec.ts'],
    globals: true,
    coverage: {
      provider: 'v8',
      reporter: ['json-summary', 'text'],
      include: ['src/**/*.ts'],
      exclude: ['src/**/*.spec.ts'],
    },
  },
});

