const calculateClaimPayout = (step: ClaimStep, policy: Policy): ClaimResult => {
  let totalPayout = 0;
  for (const damage of step.incident.damages) {
    const policyItem = policy.items.find((i) => i.type === damage.itemType);
    if (!policyItem) {
      throw new Error(`Claim references item type not in policy: ${damage.itemType}`);
    }
    if (damage.amount < 0) {
      throw new Error(`Negative damage amount: ${damage.amount}`);
    }
    let reimbursement = damage.amount;
    if (policyItem.enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD) {
      reimbursement = damage.amount * CLAIM_HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
    }
    totalPayout += Math.max(0, reimbursement - DEDUCTIBLE);
  }
  totalPayout = Math.floor(totalPayout);
  totalPayout = Math.min(totalPayout, policy.remainingCap);
  policy.remainingCap -= totalPayout;
  return { payout: totalPayout, remainingCap: policy.remainingCap };

