        policy: 0,
        incident: {
          cause: "fire",
          damages: [{ itemType: "sword", amount: 500 }],
        },
      },
    ],
  });
  const { stdout } = await execFileAsync("npx", ["tsx", "src/cli.ts"], {
    input,
  });
  const result = JSON.parse(stdout);
  expect(result).toEqual({
    results: [
      { premium: 115 },
      { payout: 400, remainingCap: 1600 },
