160	      policies[index] = { items: step.items, insuranceSum, remainingCap: insuranceSum * CAP_MULTIPLIER };
161	      quoteCount++;
162	      return { premium };
163	    }
164	    return calculateClaimPayout(step, policies[step.policy]);
165	  });
